import{_ as e,o as a,c as n,ag as s}from"./chunks/framework.6MCaaFDc.js";const h=JSON.parse('{"title":"Database Design","description":"","frontmatter":{},"headers":[],"relativePath":"theory/databases/database-design.md","filePath":"theory/databases/database-design.md"}'),r={name:"theory/databases/database-design.md"};function i(d,t,o,l,p,c){return a(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="database-design" tabindex="-1">Database Design <a class="header-anchor" href="#database-design" aria-label="Permalink to &quot;Database Design&quot;">​</a></h1><p>A well-designed database stores data efficiently, without redundancy, and makes it easy to retrieve exactly what you need. Poor design leads to duplicate data, inconsistencies, and queries that return wrong results. Getting the design right before writing a single line of SQL is essential.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11</p><p>Database design (ERDs, entities, relationships, keys) is a Grade 11 topic. Normalisation (the formal design process) is covered at Grade 12.</p></div><hr><h2 id="database-design-process" tabindex="-1">Database Design Process <a class="header-anchor" href="#database-design-process" aria-label="Permalink to &quot;Database Design Process&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Requirements analysis → Conceptual design (ERD) → Logical design (tables, keys) → Physical design (create tables in DBMS) → Implementation → Testing</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol><li><strong>Identify entities</strong> — what &quot;things&quot; does the database need to store?</li><li><strong>Identify attributes</strong> — what properties does each entity have?</li><li><strong>Identify relationships</strong> — how do entities relate to each other?</li><li><strong>Draw ERD</strong> — visual representation of the design</li><li><strong>Map to tables</strong> — convert ERD to actual tables with primary and foreign keys</li><li><strong>Normalise</strong> — apply normalisation rules to eliminate redundancy</li></ol><hr><h2 id="entities-and-attributes" tabindex="-1">Entities and Attributes <a class="header-anchor" href="#entities-and-attributes" aria-label="Permalink to &quot;Entities and Attributes&quot;">​</a></h2><p><strong>Entity</strong> — a real-world object or concept about which we store data<br><strong>Attribute</strong> — a property or characteristic of an entity<br><strong>Instance</strong> — one specific occurrence of an entity (one row in a table)</p><table tabindex="0"><thead><tr><th>Entity</th><th>Attributes</th></tr></thead><tbody><tr><td><strong>Student</strong></td><td>StudentID, FirstName, Surname, DateOfBirth, Grade</td></tr><tr><td><strong>Subject</strong></td><td>SubjectCode, SubjectName, Department</td></tr><tr><td><strong>Teacher</strong></td><td>TeacherID, FirstName, Surname, Email</td></tr><tr><td><strong>Mark</strong></td><td>MarkID, Mark, Date, StudentID (FK), SubjectCode (FK)</td></tr></tbody></table><hr><h2 id="entity-relationship-diagrams-erds" tabindex="-1">Entity-Relationship Diagrams (ERDs) <a class="header-anchor" href="#entity-relationship-diagrams-erds" aria-label="Permalink to &quot;Entity-Relationship Diagrams (ERDs)&quot;">​</a></h2><p>An <strong>ERD</strong> is a visual diagram showing entities, their attributes, and how they relate to each other.</p><h3 id="erd-notation" tabindex="-1">ERD Notation <a class="header-anchor" href="#erd-notation" aria-label="Permalink to &quot;ERD Notation&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────┐         ┌─────────────┐</span></span>
<span class="line"><span>│   STUDENT   │────────&gt;│    MARK     │</span></span>
<span class="line"><span>│             │  1:M    │             │</span></span>
<span class="line"><span>│ StudentID   │         │ MarkID (PK) │</span></span>
<span class="line"><span>│ FirstName   │         │ Mark        │</span></span>
<span class="line"><span>│ Surname     │         │ Date        │</span></span>
<span class="line"><span>│ Grade       │         │ StudentID   │</span></span>
<span class="line"><span>└─────────────┘         └─────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p><strong>Crow&#39;s foot notation</strong> (used in professional ERDs):</p><table tabindex="0"><thead><tr><th>Symbol</th><th>Meaning</th></tr></thead><tbody><tr><td>Single line <code>─</code></td><td>One</td></tr><tr><td>Double line <code>═</code></td><td>One and only one</td></tr><tr><td>Crow&#39;s foot <code>&lt;</code></td><td>Many</td></tr><tr><td>Circle <code>○</code></td><td>Zero or one</td></tr></tbody></table><hr><h2 id="relationships" tabindex="-1">Relationships <a class="header-anchor" href="#relationships" aria-label="Permalink to &quot;Relationships&quot;">​</a></h2><h3 id="one-to-one-1-1" tabindex="-1">One-to-One (1:1) <a class="header-anchor" href="#one-to-one-1-1" aria-label="Permalink to &quot;One-to-One (1:1)&quot;">​</a></h3><p>Each record in table A relates to exactly one record in table B.</p><p><strong>Example:</strong> One Student ↔ One Locker</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Student ──── Locker</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Relatively rare in databases — often combined into one table.</p><h3 id="one-to-many-1-m-←-most-common" tabindex="-1">One-to-Many (1:M) ← Most common <a class="header-anchor" href="#one-to-many-1-m-←-most-common" aria-label="Permalink to &quot;One-to-Many (1:M) ← Most common&quot;">​</a></h3><p>Each record in table A relates to many records in table B; each record in B relates to one record in A.</p><p><strong>Example:</strong> One Student → Many Marks; One Teacher → Many Classes</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Student ──&lt;&lt; Mark</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Implemented with a <strong>foreign key</strong> in the &quot;many&quot; table.</p><h3 id="many-to-many-m-m" tabindex="-1">Many-to-Many (M:M) <a class="header-anchor" href="#many-to-many-m-m" aria-label="Permalink to &quot;Many-to-Many (M:M)&quot;">​</a></h3><p>Each record in A relates to many in B, and vice versa.</p><p><strong>Example:</strong> Students enrol in many Subjects; Subjects have many Students</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Student &gt;&gt;──&lt;&lt; Subject</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><strong>Cannot be implemented directly</strong> — requires a <strong>junction table (linking table)</strong>:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>STUDENT          ENROLMENT           SUBJECT</span></span>
<span class="line"><span>StudentID ──── StudentID (FK)    SubjectCode (FK) ──── SubjectCode</span></span>
<span class="line"><span>               SubjectCode (FK)</span></span>
<span class="line"><span>               EnrolmentDate</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>The junction table holds both foreign keys (which together form a composite primary key).</p><hr><h2 id="primary-keys" tabindex="-1">Primary Keys <a class="header-anchor" href="#primary-keys" aria-label="Permalink to &quot;Primary Keys&quot;">​</a></h2><p>A <strong>primary key (PK)</strong> uniquely identifies each record in a table.</p><p><strong>Requirements:</strong></p><ul><li>Must be <strong>unique</strong> — no two records share the same PK value</li><li>Must be <strong>not NULL</strong> — cannot be empty</li><li>Must be <strong>stable</strong> — should not change over time</li><li>Should be <strong>simple</strong> — ideally a single field</li></ul><p><strong>Types of primary keys:</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Natural key</strong></td><td>An existing attribute that is naturally unique</td><td>SA ID Number, Email address</td></tr><tr><td><strong>Surrogate key</strong></td><td>An artificial unique identifier added to the table</td><td>Auto-number (1001, 1002, 1003...)</td></tr><tr><td><strong>Composite key</strong></td><td>Two or more fields combined to form a unique identifier</td><td>StudentID + SubjectCode in a junction table</td></tr></tbody></table><p><strong>Why surrogate keys are preferred:</strong></p><ul><li>Natural keys can change (email addresses change)</li><li>Natural keys can be long (SA ID is 13 digits)</li><li>Surrogate keys are simple integers — fast to join and index</li></ul><hr><h2 id="foreign-keys" tabindex="-1">Foreign Keys <a class="header-anchor" href="#foreign-keys" aria-label="Permalink to &quot;Foreign Keys&quot;">​</a></h2><p>A <strong>foreign key (FK)</strong> is a field in one table that references the primary key of another table.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>STUDENT table:    StudentID (PK) | FirstName | Surname</span></span>
<span class="line"><span>MARK table:       MarkID (PK) | Mark | Date | StudentID (FK → Student.StudentID)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>Rules:</strong></p><ul><li>FK value must exist as a PK in the referenced table (<strong>referential integrity</strong>)</li><li>FK can be NULL (if the relationship is optional)</li><li>Multiple FKs can exist in one table</li></ul><hr><h2 id="worked-example-school-database-erd" tabindex="-1">Worked Example: School Database ERD <a class="header-anchor" href="#worked-example-school-database-erd" aria-label="Permalink to &quot;Worked Example: School Database ERD&quot;">​</a></h2><p><strong>Scenario:</strong> A school needs to track students, subjects, teachers, and marks.</p><p><strong>Entities identified:</strong></p><ul><li>Student</li><li>Subject</li><li>Teacher</li><li>Enrolment (junction: Student ↔ Subject)</li><li>Mark</li></ul><p><strong>ERD:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>TEACHER                     SUBJECT</span></span>
<span class="line"><span>TeacherID (PK)──────1:M──&gt;SubjectCode (PK)</span></span>
<span class="line"><span>FirstName                  SubjectName</span></span>
<span class="line"><span>Surname                    TeacherID (FK)</span></span>
<span class="line"><span>Email</span></span>
<span class="line"><span>                               |</span></span>
<span class="line"><span>                              1:M (via junction)</span></span>
<span class="line"><span>                               |</span></span>
<span class="line"><span>STUDENT ────M:M──── ENROLMENT ──────&gt; MARK</span></span>
<span class="line"><span>StudentID (PK)      StudentID (FK)     MarkID (PK)</span></span>
<span class="line"><span>FirstName           SubjectCode (FK)   Mark</span></span>
<span class="line"><span>Surname             EnrolmentDate      Date</span></span>
<span class="line"><span>Grade                                  StudentID (FK)</span></span>
<span class="line"><span>                                       SubjectCode (FK)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p><strong>Tables:</strong></p><table tabindex="0"><thead><tr><th>STUDENT</th><th></th><th>SUBJECT</th><th></th><th>ENROLMENT</th><th></th><th>MARK</th></tr></thead><tbody><tr><td>StudentID (PK)</td><td></td><td>SubjectCode (PK)</td><td></td><td>StudentID (PK, FK)</td><td></td><td>MarkID (PK)</td></tr><tr><td>FirstName</td><td></td><td>SubjectName</td><td></td><td>SubjectCode (PK, FK)</td><td></td><td>Mark</td></tr><tr><td>Surname</td><td></td><td>TeacherID (FK)</td><td></td><td>EnrolmentDate</td><td></td><td>Date</td></tr><tr><td>Grade</td><td></td><td></td><td></td><td></td><td></td><td>StudentID (FK)</td></tr><tr><td></td><td></td><td></td><td></td><td></td><td></td><td>SubjectCode (FK)</td></tr></tbody></table><hr><h2 id="data-dictionary" tabindex="-1">Data Dictionary <a class="header-anchor" href="#data-dictionary" aria-label="Permalink to &quot;Data Dictionary&quot;">​</a></h2><p>A <strong>data dictionary</strong> documents every field in every table:</p><table tabindex="0"><thead><tr><th>Field</th><th>Table</th><th>Data Type</th><th>Size</th><th>Constraints</th><th>Description</th></tr></thead><tbody><tr><td>StudentID</td><td>Student</td><td>AutoNumber</td><td></td><td>PK, Not Null</td><td>Unique student identifier</td></tr><tr><td>FirstName</td><td>Student</td><td>Text</td><td>50</td><td>Not Null</td><td>Student&#39;s first name</td></tr><tr><td>Grade</td><td>Student</td><td>Integer</td><td></td><td>10–12</td><td>Current grade level</td></tr><tr><td>Mark</td><td>Mark</td><td>Integer</td><td></td><td>0–100</td><td>Assessment mark</td></tr><tr><td>Date</td><td>Mark</td><td>Date</td><td></td><td>Not Null</td><td>Date assessment written</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Entity</strong></td><td>Real-world object about which data is stored</td></tr><tr><td><strong>Attribute</strong></td><td>Property of an entity</td></tr><tr><td><strong>ERD</strong></td><td>Entity-Relationship Diagram — visual database design</td></tr><tr><td><strong>Primary key</strong></td><td>Field(s) uniquely identifying each record</td></tr><tr><td><strong>Foreign key</strong></td><td>Field referencing the PK of another table</td></tr><tr><td><strong>Junction table</strong></td><td>Table resolving a many-to-many relationship</td></tr><tr><td><strong>Composite key</strong></td><td>Primary key made up of two or more fields</td></tr><tr><td><strong>Surrogate key</strong></td><td>Artificial PK (auto-number) not derived from data</td></tr><tr><td><strong>Natural key</strong></td><td>PK from existing real-world data</td></tr><tr><td><strong>Data dictionary</strong></td><td>Documentation of every field in the database</td></tr><tr><td><strong>Referential integrity</strong></td><td>Rule that FK values must match existing PK values</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is an entity? Give an example.&quot;</strong> — A real-world object about which data is stored; example: Student, Teacher, Product, Order</p></li><li><p><strong>&quot;What is the difference between a primary key and a foreign key?&quot;</strong> — PK uniquely identifies each record in its own table; FK references the PK of another table to establish a link</p></li><li><p><strong>&quot;How is a many-to-many relationship implemented in a relational database?&quot;</strong> — Using a junction (linking) table that contains the foreign keys of both related tables</p></li><li><p><strong>&quot;Give TWO requirements for a primary key&quot;</strong> — Must be unique (no two records have the same value); must not be NULL; must be stable (not change over time)</p></li><li><p><strong>&quot;A student can take many subjects and a subject can have many students. What type of relationship is this? How would you implement it?&quot;</strong> — Many-to-many; implement using a junction table (e.g. Enrolment) with StudentID and SubjectCode as foreign keys</p></li></ol></div>`,71)])])}const b=e(r,[["render",i]]);export{h as __pageData,b as default};
